[{'doi}': '从 Arxiv ID 获取 URL\ndef get_url_from_arxiv(arxiv_id):\n    return f', 'https': 'arxiv.org/abs/{arxiv_id'}, ["ws]', '', title)  # 移除标点\n    return ' '.join(title.split())  # 移除多余空格\n\n# 使用 ACL Anthology 查询论文 URL\ndef get_acl_anthology_url(title):\n    simplified_title = simplify_title(title)\n    search_url = f", "https://aclanthology.org/search/?q={simplified_title.replace(' ', '+')}", "try:\n        response = requests.get(search_url)\n        if response.status_code == 200:\n            soup = BeautifulSoup(response.text, 'html.parser')\n            # 获取多个搜索结果\n            results = soup.find_all('a', href=True)\n            for result in results:\n                if 'papers' in result['href']:\n                    # 获取链接文本进行比较\n                    result_title = result.text.strip().lower()\n                    if compare_titles(title.lower(), result_title):\n                        return f", 'https://aclanthology.org{result[\'href\']}"\n        print(f"No ACL Anthology URL found for title: {title}")\n    except Exception as e:\n        print(f"Error searching ACL Anthology for title \'{title}\': {e}', 'return None\n\n# 使用 Crossref API 获取 DOI 或 URL\ndef get_doi_from_title_and_conference(title, conference=None):\n    cr = Crossref()\n    query = title\n    if conference:\n        normalized_conference = normalize_conference_name(conference)\n        query = f"{title} {normalized_conference}', 'try:\n        result = cr.works(query=query, limit=3)\n        for item in result[\'message\'][\'items\']:\n            fetched_title = item.get(\'title\', [\'\'])[0]\n            if compare_titles(title, fetched_title):\n                return item.get(\'DOI\', None)\n    except Exception as e:\n        print(f"Error fetching DOI for title \'{title}\' (conference \'{conference}\'): {e}', 'return None\n\n# 使用 Arxiv API 搜索论文 URL\ndef get_arxiv_url_by_title(title):\n    # 构建arxiv搜索URL\n    search_query = title.replace(\' \', \'+\')\n    api_url = f"http://export.arxiv.org/api/query?search_query={search_query}&start=0&max_results=3', 'try:\n        response = requests.get(api_url)\n        if response.status_code == 200:\n            # 解析XML响应\n            soup = BeautifulSoup(response.content, "xml', '查找所有条目\n            entries = soup.find_all(\'entry\')\n            for entry in entries:\n                # 获取标题\n                arxiv_title = entry.find(\'title\').text.strip()\n                # 比较标题相似度\n                if compare_titles(title, arxiv_title):\n                    # 获取arxiv ID并构建URL\n                    arxiv_id = entry.find(\'id\').text.split(\'/abs/\')[-1]\n                    return f\'https://arxiv.org/abs/{arxiv_id}\'\n        print(f"No Arxiv URL found for title: {title}")\n    except Exception as e:\n        print(f"Error searching Arxiv for title \'{title}\': {e}', 'return None\n\n# 标题相似度比较\ndef compare_titles(original_title, fetched_title, threshold=0.85):\n    original_title = clean_title(original_title)\n    fetched_title = clean_title(fetched_title)\n    similarity = difflib.SequenceMatcher(None, original_title, fetched_title).ratio()\n    return similarity >= threshold\n\n# 清理标题中的特殊符号\ndef clean_title(title):\n    return title.lower().replace(\'{\', \'\').replace(\'}\', \'\').replace(\'\n\', \'\').strip()\n\n# 从 journal 字段中提取 Arxiv ID\ndef extract_arxiv_id(entry):\n    # 1) 优先从 journal 字段中解析形如 "arXiv:YYMM.NNNNN', "的编号\n    if 'journal' in entry:\n        journal = entry['journal']\n        arxiv_match = re.search(r'arxiv[:s]*([d.]+)', journal, re.IGNORECASE)\n        if arxiv_match:\n            return arxiv_match.group(1)\n\n    # 2) 若 journal 未解析到，再尝试从 arxivid 字段读取（仅当存在且非空）\n    arxiv_id_field = entry.get('arxivid')\n    if arxiv_id_field is not None:\n        arxiv_id = arxiv_id_field.strip()\n        if arxiv_id:\n            return arxiv_id\n\n    return None\n\n# 解析 .bib 文件\ndef fill_bib_urls(bib_file):\n    with open(bib_file, 'r', encoding='utf-8') as bibtex_file:\n        bib_database = bibtexparser.load(bibtex_file)\n\n    # 遍历每个条目\n    for entry in bib_database.entries:\n        if 'url' not in entry:\n            # 先检查是否为 Arxiv 论文\n            arxiv_id = extract_arxiv_id(entry)\n            if arxiv_id:\n                entry['url'] = get_url_from_arxiv(arxiv_id)\n                print(f", "Arxiv URL added for {entry.get('title', 'No Title')}", "else:\n                booktitle = entry.get('booktitle', None)\n                title = entry.get('title', None)\n                if booktitle and title:\n                    # 先通过 ACL Anthology 查询 URL\n                    url = get_acl_anthology_url(title)\n                    if url:\n                        entry['url'] = url\n                        print(f", "ACL Anthology URL added for {entry.get('title', 'No Title')}", "else:\n                        # 如果 ACL Anthology 未找到结果，使用 Crossref API 查询 DOI\n                        doi = get_doi_from_title_and_conference(title, booktitle)\n                        if doi:\n                            entry['doi'] = doi\n                            entry['url'] = get_url_from_doi(doi)\n                            print(f", 'Conference URL added for {entry.get(\'title\', \'No Title\')}")\n                        else:\n                            # 如果所有方法都失败了，尝试通过arxiv搜索\n                            print(f', 'DOI not found for title: {title} (conference: {booktitle}), trying Arxiv search', "arxiv_url = get_arxiv_url_by_title(title)\n                            if arxiv_url:\n                                entry['url'] = arxiv_url\n                                print(f", 'Arxiv URL added for {entry.get(\'title\', \'No Title\')}")\n                            else:\n                                print(f"No URL found for title: {title} (conference: {booktitle})', "else:\n                    # 如果没有 Arxiv ID 或会议信息，尝试通过标题查找 DOI\n                    title = entry.get('title', None)\n                    if title:\n                        doi = get_doi_from_title_and_conference(title)\n                        if doi:\n                            entry['doi'] = doi\n                            entry['url'] = get_url_from_doi(doi)\n                        else:\n                            # 如果DOI未找到，尝试通过arxiv搜索\n                            print(f", 'DOI not found for title: {title}, trying Arxiv search', "arxiv_url = get_arxiv_url_by_title(title)\n                            if arxiv_url:\n                                entry['url'] = arxiv_url\n                                print(f", 'Arxiv URL added for {entry.get(\'title\', \'No Title\')}")\n                            else:\n                                print(f"No URL found for title: {title}', "保存修改后的 .bib 文件\n    with open(bib_file, 'w', encoding='utf-8') as bibtex_file:\n        bibtexparser.dump(bib_database, bibtex_file)\n\n# 示例：自动填充 url 字段\nfill_bib_urls('citations.bib')"]]